import{_ as e,o as a,c as i,ag as o}from"./chunks/framework.eQLvDOR_.js";const _=JSON.parse('{"title":"artifact-driven-decomposition","description":"","frontmatter":{"title":"artifact-driven-decomposition","concept":"产物驱动的任务拆解","concept_id":"artifact-driven-decomposition","aliases":[],"sources":["02_Library/AI_IDE_And_CLI/[AI_IDE_And_CLI] Run multiple agents at once with _fleet in Copilot CLI.md"],"related_concepts":["[[multi-agent-orchestrator]]"],"created_at":"2026-04-18","last_compiled":"2026-04-18"},"headers":[],"relativePath":"wiki/concepts/artifact-driven-decomposition.md","filePath":"wiki/concepts/artifact-driven-decomposition.md","lastUpdated":null}'),r={name:"wiki/concepts/artifact-driven-decomposition.md"};function n(c,t,l,s,d,h){return a(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="产物驱动的任务拆解-artifact-driven-decomposition" tabindex="-1">产物驱动的任务拆解 (Artifact-Driven Decomposition) <a class="header-anchor" href="#产物驱动的任务拆解-artifact-driven-decomposition" aria-label="Permalink to &quot;产物驱动的任务拆解 (Artifact-Driven Decomposition)&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>在向支持多 Agent 并发处理的引擎派发指令时，把指令意图从“抽象动作”重构为“具体的特定产物要求（特定文件/文档/报告）”，以方便中心调配器正确并行派发和验证。</p><h2 id="核心要点" tabindex="-1">核心要点 <a class="header-anchor" href="#核心要点" aria-label="Permalink to &quot;核心要点&quot;">​</a></h2><ul><li><strong>将过程描述转换为结构化交付标准</strong>：给出的目标指令需精确挂靠到“产生什么文件”。（来源：<a href="/s/webclips/library/AI_IDE_And_CLI/AI_IDE_And_CLI - Run multiple agents at once with _fleet in Copilot CLI.html">[AI_IDE_And_CLI] Run multiple agents at once...</a>）</li><li><strong>强行隔离上下文污染</strong>：由于模型能够提前知晓不同的交付件不共享上下文节点，它能在初期规划出最佳的独立子流向，减少“串行化执行”。</li></ul><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><p><strong>错误 Prompt</strong>：“帮我建立此系统的说明指导” <strong>正确 Prompt</strong>：“创建 /docs/auth.md 包括令牌控制逻辑、创建 /docs/api_list.md 具体接口清单。在并行任务都结束后，再依赖生成汇总索引 /docs/index.md”。为各个物理层面的文档圈定互不干涉的安全区是最关键的。</p><h2 id="关联概念" tabindex="-1">关联概念 <a class="header-anchor" href="#关联概念" aria-label="Permalink to &quot;关联概念&quot;">​</a></h2><ul><li><a href="/s/webclips/wiki/concepts/multi-agent-orchestrator.html">multi-agent-orchestrator</a> — 此方式极度契合并并发机制，因为明确目标边界是触发 Orchestrator 安全下发子节点的大前提。</li></ul><h2 id="源文章引用" tabindex="-1">源文章引用 <a class="header-anchor" href="#源文章引用" aria-label="Permalink to &quot;源文章引用&quot;">​</a></h2><table tabindex="0"><thead><tr><th>来源</th><th>关键段落摘录</th></tr></thead><tbody><tr><td><a href="/s/webclips/library/AI_IDE_And_CLI/AI_IDE_And_CLI - Run multiple agents at once with _fleet in Copilot CLI.html">[AI_IDE_And_CLI] Run multiple agents at once...</a></td><td>&quot;A good way to do that is being specific about deliverables. Map every work item to a concrete artifact like a file, a test suite, or a section of documentation... The second prompt gives the orchestrator four distinct deliverables, three of which can run in parallel, and one that depends on them.&quot;</td></tr></tbody></table>',11)])])}const m=e(r,[["render",n]]);export{_ as __pageData,m as default};
